            object b64_5 = "YQ=="; // a
            object binary5 = exchange.base64ToBinary(b64_5);
            Assert(isEqual(exchange.binaryToBase64(binary5), b64_5));
            // Test 6: Two bytes
            object b64_6 = "YWI="; // ab
            object binary6 = exchange.base64ToBinary(b64_6);
