            object b64_7 = "YWJj"; // abc
            object binary7 = exchange.base64ToBinary(b64_7);
            Assert(isEqual(exchange.binaryToBase64(binary7), b64_7));
            // Test 8: JSON-like binary
            object b64_8 = "eyJrZXkiOiJ2YWx1ZSJ9"; // {"key":"value"}
